import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import axios from 'axios';
import { SunIcon, BellIcon, EnvelopeIcon } from '@heroicons/react/24/outline';

const Settings = () => {
  const { user, setUser } = useAuth();
  const [loading, setLoading] = useState(false);
  const [settings, setSettings] = useState({
    notifications: true,
    emailAlerts: true
  });

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/users/settings');
      const data = res.data.data;
      setSettings({
        notifications: data.notifications !== undefined ? data.notifications : true,
        emailAlerts: data.emailAlerts !== undefined ? data.emailAlerts : true
      });
    } catch (error) {
      console.error('Error fetching settings:', error);
    }
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // Always use 'light' theme
      const updatedSettings = { ...settings, theme: 'light' };
      const res = await axios.put('http://localhost:5000/api/users/settings', updatedSettings);
      toast.success(res.data.message || 'Settings updated successfully!');
      
      if (user) {
        setUser({ ...user, settings: updatedSettings });
      }
    } catch (error) {
      console.error('Update error:', error);
      toast.error(error.response?.data?.message || 'Failed to update settings');
    } finally {
      setLoading(false);
    }
  };

  const handleToggle = (key) => {
    setSettings({ ...settings, [key]: !settings[key] });
  };

  return (
    <div className="max-w-2xl mx-auto">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Settings</h1>

      <div className="glass-card">
        <form onSubmit={handleUpdate} className="space-y-6">
          {/* Theme - Always Light */}
          <div className="p-4 bg-gradient-to-r from-gold-light/20 to-white rounded-lg border border-gold/30">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-gold rounded-lg">
                <SunIcon className="w-5 h-5 text-white" />
              </div>
              <div>
                <h3 className="font-medium text-gray-900">Light Theme</h3>
                <p className="text-sm text-gray-500">Elegant white and gold design</p>
              </div>
              <span className="ml-auto text-xs font-medium text-gold bg-gold-light px-3 py-1 rounded-full">Active</span>
            </div>
          </div>

          <hr className="border-gray-200" />

          {/* Push Notifications */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <BellIcon className="w-5 h-5 text-gray-400" />
              <div>
                <h3 className="text-sm font-medium text-gray-900">Push Notifications</h3>
                <p className="text-sm text-gray-500">Receive notifications for task updates</p>
              </div>
            </div>
            <label className="relative inline-flex items-center cursor-pointer">
              <input
                type="checkbox"
                checked={settings.notifications}
                onChange={() => handleToggle('notifications')}
                className="sr-only peer"
              />
              <div className="w-11 h-6 bg-gray-200 peer-focus:ring-2 peer-focus:ring-gold rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-gold"></div>
            </label>
          </div>

          {/* Email Alerts */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <EnvelopeIcon className="w-5 h-5 text-gray-400" />
              <div>
                <h3 className="text-sm font-medium text-gray-900">Email Alerts</h3>
                <p className="text-sm text-gray-500">Receive email notifications</p>
              </div>
            </div>
            <label className="relative inline-flex items-center cursor-pointer">
              <input
                type="checkbox"
                checked={settings.emailAlerts}
                onChange={() => handleToggle('emailAlerts')}
                className="sr-only peer"
              />
              <div className="w-11 h-6 bg-gray-200 peer-focus:ring-2 peer-focus:ring-gold rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-gold"></div>
            </label>
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full btn-primary py-3 text-lg"
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                Saving...
              </span>
            ) : (
              'Save Settings'
            )}
          </button>
        </form>
      </div>

      <div className="mt-4 text-center text-sm text-gray-500">
        <p className="flex items-center justify-center gap-2">
          <span className="w-2 h-2 bg-gold rounded-full inline-block"></span>
          Light Theme Always Active
          <span className="w-2 h-2 bg-gold rounded-full inline-block"></span>
        </p>
      </div>
    </div>
  );
};

export default Settings;
